SELECT current_status, COUNT(feature_id) AS count_of_features
FROM features
GROUP BY current_status;

SELECT u.username, u.role
FROM users u
JOIN permissions p ON u.role = p.role;

SELECT COUNT(*) 
FROM features 
WHERE current_status = 'Now';

SELECT features.feature_name, statuses.status_name
FROM features
INNER JOIN statuses ON features.current_status = statuses.status_name;

SELECT feature_id, MAX(update_date) AS latest_update_date
FROM feature_updates
GROUP BY feature_id;

SELECT feature_id, feature_name 
FROM features 
WHERE feature_id NOT IN (SELECT feature_id FROM feature_updates);
